# Base shape module - provides abstract base class for geometric shapes
@abstract
class Shape:
    _name: str = "Shape"

    @abstract
    def get_area(self) -> float:
        ...

    def describe(self) -> str:
        return f"{self._name}: area = {self.get_area()}"

